using System.Text.RegularExpressions;

namespace Contoso.Text;

public sealed class StringFormatter
{
    public string FormatPhoneNumber(string digits)
    {
        ArgumentNullException.ThrowIfNull(digits);
        if (digits.Length != 10)
            throw new ArgumentException("Must be exactly 10 digits.", nameof(digits));
        return $"({digits[..3]}) {digits[3..6]}-{digits[6..]}";
    }

    public string BuildGreeting(string name, string title = "Mr.")
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(name);
        return $"Dear {title} {name},";
    }

    public string GenerateSlug(string title)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(title);
        return Regex.Replace(title.Trim().ToLowerInvariant(), @"[^a-z0-9]+", "-").Trim('-');
    }

    public string FormatCurrency(decimal amount, string symbol = "$")
    {
        return $"{symbol}{amount:F2}";
    }
}

using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // --- FormatPhoneNumber ---

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.AreEqual("(555) 123-4567", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        Assert.StartsWith("(800)", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        Assert.EndsWith("1234", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDash()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.Contains("-", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    [DataRow("123", DisplayName = "Too short")]
    [DataRow("12345678901", DisplayName = "Too long")]
    [DataRow("", DisplayName = "Empty")]
    public void FormatPhoneNumber_InvalidLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.FormatPhoneNumber(digits));
    }

    // --- BuildGreeting ---

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_ReturnsGreeting()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.StartsWith("Dear Dr.", result);
    }

    [TestMethod]
    public void BuildGreeting_AnyName_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Williams", "Ms.");

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_ContainsName()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.Contains("Johnson", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_NullOrWhitespaceName_Throws(string? name)
    {
        Assert.ThrowsException<ArgumentException>(() => _formatter.BuildGreeting(name!));
    }

    // --- GenerateSlug ---

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseHyphenated()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_ContainsOnlySlugChars()
    {
        var result = _formatter.GenerateSlug("C# is Great!!!");

        Assert.MatchesRegex(@"^[a-z0-9\-]+$", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleStartingWithSpaces_DoesNotStartWithHyphen()
    {
        var result = _formatter.GenerateSlug("  Leading Spaces");

        Assert.StartsWith("leading", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleEndingWithSpecialChars_DoesNotEndWithHyphen()
    {
        var result = _formatter.GenerateSlug("Trailing!!!");

        Assert.EndsWith("trailing", result);
    }

    [TestMethod]
    [DataRow("My Blog Post", "my-blog-post")]
    [DataRow("UPPER CASE", "upper-case")]
    [DataRow("already-slugged", "already-slugged")]
    [DataRow("  extra   spaces  ", "extra-spaces")]
    public void GenerateSlug_VariousInputs_ReturnsExpected(string input, string expected)
    {
        var result = _formatter.GenerateSlug(input);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_NullOrWhitespace_Throws(string? title)
    {
        Assert.ThrowsException<ArgumentException>(() => _formatter.GenerateSlug(title!));
    }

    // --- FormatCurrency ---

    [TestMethod]
    public void FormatCurrency_PositiveAmount_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(19.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(50m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(100m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_ReturnsFormattedString()
    {
        var result = _formatter.FormatCurrency(9.5m);

        Assert.AreEqual("$9.50", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinusSign()
    {
        var result = _formatter.FormatCurrency(-25.50m);

        Assert.Contains("-", result);
    }
}

