     // --- GenerateSlug ---

     [TestMethod]
     public void GenerateSlug_SimpleTitle_ReturnsLowercaseHyphenated()
     {
         var result = _formatter.GenerateSlug("Hello World");

         Assert.AreEqual("hello-world", result);
     }

     [TestMethod]
     public void GenerateSlug_TitleWithSpecialChars_ContainsOnlySlugChars()
     {
         var result = _formatter.GenerateSlug("C# is Great!!!");

         Assert.MatchesRegex(@"^[a-z0-9\-]+$", result);
     }

     [TestMethod]
     public void GenerateSlug_TitleStartingWithSpaces_DoesNotStartWithHyphen()
     {
         var result = _formatter.GenerateSlug("  Leading Spaces");

         Assert.StartsWith("leading", result);
     }

     [TestMethod]
     public void GenerateSlug_TitleEndingWithSpecialChars_DoesNotEndWithHyphen()
     {
         var result = _formatter.GenerateSlug("Trailing!!!");

         Assert.EndsWith("trailing", result);
     }

     [TestMethod]
     [DataRow("My Blog Post", "my-blog-post")]
     [DataRow("UPPER CASE", "upper-case")]
     [DataRow("already-slugged", "already-slugged")]
     [DataRow("  extra   spaces  ", "extra-spaces")]
     public void GenerateSlug_VariousInputs_ReturnsExpected(string input, string expected)
     {
         var result = _formatter.GenerateSlug(input);

         Assert.AreEqual(expected, result);
     }

     [TestMethod]
     [DataRow(null)]
     [DataRow("")]
     [DataRow("   ")]
     public void GenerateSlug_NullOrWhitespace_Throws(string? title)
     {
         Assert.Throws<ArgumentException>(() => _formatter.GenerateSlug(title!));
     }

